window.registerPlugin("com.klab.mattermost-command-center",new class{initialize(e,t){this.registry=e,this.store=t,e.registerPostDropdownMenuAction("Create Task in Plane",this.handleCreateTask.bind(this))}async handleCreateTask(e){try{const t=await fetch("/plugins/com.klab.mattermost-command-center/api/v1/action/create-task-from-message",{method:"POST",headers:{"Content-Type":"application/json"},credentials:"include",body:JSON.stringify({post_id:e})});if(!t.ok){const e=await t.json();return void console.error("MCC: Failed to create task from message:",e.error||t.statusText)}const a=await t.json();this.store.dispatch({type:"RECEIVED_DIALOG",data:{url:a.url,dialog:a.dialog}})}catch(e){console.error("MCC: Error in create task from message:",e)}}uninitialize(){}});